  .compact-item-table {
    font-size: 9px;
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
  }

  .compact-item-table th,
  .compact-item-table td {
    padding: 1px;
    border: 1px solid #ccc;
    text-align: left;
    vertical-align: top;
    word-wrap: break-word;
  }

  .item-title {
    font-weight: bold;
    word-wrap: break-word;
  }

  .text-right {
    text-align: right;
  }

  .text-center {
    text-align: center;
  }
</style>

<table class="compact-item-table">
  <thead>
    <tr>
      <th style="width: 4%;">#</th>
      <th style="width: 34%;">Description of Goods<br>Product Code<br>HSN/SAC<br>Sale UOM to Stock UOM conv. factor</th>
      <th style="width: 8%;">Sale Qty<br><br>Sale UOM</th>
      <th style="width: 8%;">Qty in Stock UOM<br><br>Stock UOM</th>
      <th style="width: 6%;">Rate<br>({{ doc.currency }})</th>
      <th style="width: 8%;">Taxable Value<br>({{ doc.currency }})</th>
      <!-- <th style="width: 8%;">CGST %<br><br>Amt</th>
      <th style="width: 8%;">SGST %<br><br>Amt</th>
      <th style="width: 8%;">IGST %<br><br>Amt</th>
      <th style="width: 8%;">Amt Incl. Tax<br>({{ doc.currency }})</th> -->
    </tr>
  </thead>
  <tbody>
    {% for item in doc.items %}
    {% set total_amount = (item.amount or 0) + (item.igst_amount or 0) + (item.cgst_amount or 0) + (item.sgst_amount or
    0) %}
    <tr>
      <td>{{ loop.index }}.</td>
      <td>
        <span class="item-title">{{ item.item_name }}</span><br>
        {{ item.item_code }}<br>
        {{ item.gst_hsn_code or "" }}<br>
        {{ item.conversion_factor | abs or ""}}
      </td>
      <td class="text-right">{{ item.qty | abs }} <br><br>{{ item.uom or "" }}</td>
      <td class="text-right">{{ item.stock_qty | abs }} <br><br>{{ item.stock_uom or "" }}</td>
      <td class="text-right">{{ frappe.utils.fmt_money(item.rate | abs) or 0}}</td>
      <td class="text-right">{{ frappe.utils.fmt_money(item.amount | abs) or 0}}</td>
      <!-- <td class="text-right">
        {{ item.cgst_rate or 0 }}<br><br>
        {{ frappe.utils.fmt_money(item.cgst_amount | abs)}}
      </td>
      <td class="text-right">
        {{ item.sgst_rate or 0 }}<br><br>
        {{ frappe.utils.fmt_money(item.sgst_amount | abs)}}
      </td>
      <td class="text-right">
        {{ item.igst_rate or 0 }}<br><br>
        {{ frappe.utils.fmt_money(item.igst_amount | abs)}}
      </td>
      <td class="text-right">{{ frappe.utils.fmt_money(total_amount | abs) }}</td> -->
    </tr>
    {% endfor %}
  </tbody>
</table>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
  .totals-wrapper {
    width: 100%;
    margin-top: 5px;
  }

  .totals-table {
    margin-left: auto; /* aligns table to the right */
    width: 70%;
    font-size: 9px;
    border-collapse: collapse;
    table-layout: fixed;
  }

  .totals-table th,
  .totals-table td {
    width: 10%;
    text-align: left;
    vertical-align: top;
    padding-right: 1px;
    white-space: normal;
    word-wrap: break-word;
    border: none;
    background: none !important;
    line-height: 1.2;
  }

  .totals-table th {
    font-weight: normal !important;
    padding: 0;
  }

  .totals-table td b {
    font-weight: bold;
    font-size: 11px;
  }
</style>

<div class="totals-wrapper">
  <table class="totals-table">
    <thead>
      <tr>
        <th>{{ _("Total") }}</th>

        {%- for charge in doc.taxes -%}
        {%- if (charge.tax_amount) -%}
        <th>{{ charge.description or charge.account_head }}</th>
        {%- endif -%}
        {%- endfor -%}

        <th>{{ _("Total Taxes & Charges") }}</th>
        <th>{{ _("Grand Total") }}</th>
        <th>{{ _("Rounded Value") }}</th>
        <th>{{ _("Rounded Total") }}</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td>{{ doc.get_formatted("total", doc) }}</td>

        {%- for charge in doc.taxes -%}
        {%- if (charge.tax_amount) -%}
        <td>{{ charge.get_formatted("tax_amount", doc) }}</td>
        {%- endif -%}
        {%- endfor -%}

        <td>{{ doc.get_formatted("total_taxes_and_charges", doc) }}</td>
        <td><b>{{ doc.get_formatted("grand_total", doc) }}</b></td>
        <td>{{ doc.get_formatted("rounding_adjustment", doc) }}</td>
        <td><b>{{ doc.get_formatted("rounded_total", doc) }}</b></td>
      </tr>
    </tbody>
  </table>
</div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "other_charges_calculation", "print_hide": 0, "label": "Taxes and Charges Calculation"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<p style="font-size: 12px; font-weight: bold; margin: 0; padding: 0">
